QueryScript.Source:

import sailpoint.object.*;   
import sailpoint.reporting.*;   
import sailpoint.search.ExternalAttributeFilterBuilder;
import java.util.*; 
List filters = new ArrayList();							
if(value !=null){								 
	 if(null !=value.get("start")){								
		filters.add(Filter.ge("created", new Date(value.get("start"))));
	 }

	if(null !=value.get("end")){
		filters.add(Filter.le("created", new Date(value.get("end"))));
	}
}
filters.add(Filter.eq("action","identityLifecycleEvent"));
queryOptions.setFilters(filters);
queryOptions.addOrdering("string1", true); 
return queryOptions;

RenderScript.Source:
if(null != value){
	String user = value.replaceAll("Identity:","");
	renderCache.put("user", user);
	return user;
}

import sailpoint.object.Identity;
String user = (String) renderCache.get("user");
if(null != user){
	Identity id = context.getObject(Identity.class,user);
	if(null != id){
		return id.getFirstname() ;
	}
}
return "";

  import sailpoint.object.Identity;
	String user = (String) renderCache.get("user");
	if(null != user){
		Identity id = context.getObject(Identity.class,user);
		if(null != id){
			return id.getLastname();
		}
	}
	return "";

  import sailpoint.object.Identity;
	String user = (String) renderCache.get("user");
	if(null != user){
		Identity id = context.getObject(Identity.class,user);
		if(null != id){
			Identity manager = id.getManager();
			if(null !=manager){
				return manager.getDisplayName();
			}
		}
	}
	return "";
